import{_ as t,W as l,X as i,Y as a,Z as e,$ as c,a0 as n,C as s}from"./framework-174e6972.js";const r={},d=a("p",null,"Tomcat是web服务器软件，下面我们学习它的使用。",-1),p=a("h2",{id:"_1-使用步骤",tabindex:"-1"},[a("a",{class:"header-anchor",href:"#_1-使用步骤","aria-hidden":"true"},"#"),e(" 1. 使用步骤")],-1),h=a("h3",{id:"_1-1-下载",tabindex:"-1"},[a("a",{class:"header-anchor",href:"#_1-1-下载","aria-hidden":"true"},"#"),e(" 1.1. 下载")],-1),u={href:"http://tomcat.apache.org/",target:"_blank",rel:"noopener noreferrer"},b=n(`<h3 id="_1-2-安装" tabindex="-1"><a class="header-anchor" href="#_1-2-安装" aria-hidden="true">#</a> 1.2. 安装</h3><p>解压下载的压缩包即可。</p><figure><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/java/JavaWeb/01.Tomcat/60be2f31844ef46bb200848c.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><blockquote><p>注意：安装目录建议不要有中文和空格</p></blockquote><h3 id="_1-3-卸载" tabindex="-1"><a class="header-anchor" href="#_1-3-卸载" aria-hidden="true">#</a> 1.3. 卸载</h3><p>直接删除Tomcat的安装目录。</p><h3 id="_1-4-启动" tabindex="-1"><a class="header-anchor" href="#_1-4-启动" aria-hidden="true">#</a> 1.4. 启动</h3><ul><li>找到Tomcat安装目录中的bin/startup.bat文件 ，双击运行该文件即可</li><li>访问：浏览器输入<code>http://localhost:8080</code>回车访问自己。访问别人网站的格式：<code>http://别人的ip:8080</code>。</li></ul><h4 id="_1-4-1-启动可能遇到的问题" tabindex="-1"><a class="header-anchor" href="#_1-4-1-启动可能遇到的问题" aria-hidden="true">#</a> 1.4.1. 启动可能遇到的问题</h4><ol><li><p>黑窗口一闪而过：</p><ul><li>原因： 没有正确配置JAVA_HOME环境变量；</li><li>解决方案：正确配置JAVA_HOME环境变量。</li></ul></li><li><p>启动报错：</p><ul><li>暴力：找到占用的端口号，并且找到对应的进程，使用命令<code>netstat -ano</code>杀死该进程。</li><li>温柔：修改自身的端口号，找到Tomcat安装目录中的<code>conf/server.xml</code>文件，通过修改下面代码中的port修改端口。</li></ul></li></ol><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token operator">&lt;</span><span class="token class-name">Connector</span> port<span class="token operator">=</span><span class="token string">&quot;8888&quot;</span> protocol<span class="token operator">=</span><span class="token string">&quot;HTTP/1.1&quot;</span>
    connectionTimeout<span class="token operator">=</span><span class="token string">&quot;20000&quot;</span>
    redirectPort<span class="token operator">=</span><span class="token string">&quot;8445&quot;</span> <span class="token operator">/</span><span class="token operator">&gt;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p>一般会将tomcat的默认端口号修改为80。80端口号是http协议的默认端口号。好处：在访问时，就不用输入端口号。</p></blockquote><h3 id="_1-5-关闭" tabindex="-1"><a class="header-anchor" href="#_1-5-关闭" aria-hidden="true">#</a> 1.5. 关闭</h3><ol><li><p>正常关闭：</p><ul><li>找到Tomcat安装目录中的<code>bin/shutdown.bat</code>脚本文件，双击运行该脚本。</li><li>在运行<code>bin/startup.bat</code>脚本的窗口中按下组合键ctrl+c关闭。</li></ul></li><li><p>强制关闭：</p><ul><li>点击运行<code>bin/startup.bat</code>脚本窗口的×。</li></ul></li></ol><h2 id="_2-部署web项目的三种方式" tabindex="-1"><a class="header-anchor" href="#_2-部署web项目的三种方式" aria-hidden="true">#</a> 2. 部署WEB项目的三种方式</h2><h3 id="_2-1-直接进行部署的两种方式" tabindex="-1"><a class="header-anchor" href="#_2-1-直接进行部署的两种方式" aria-hidden="true">#</a> 2.1. 直接进行部署的两种方式</h3><ol><li>直接将WEB项目放到Tomcat安装目录中的webapps目录下即可。</li></ol><blockquote><p>访问路径中的hello是项目的虚拟目录，hello.html是资源名称。</p></blockquote><figure><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/java/JavaWeb/01.Tomcat/60be2bf3844ef46bb2b387d6.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><ol start="2"><li>将项目打成一个war包，再将war包放置到webapps目录下，可简化部署操作。</li></ol><blockquote><p>在tomcat服务器中，war包会自动解压缩。</p></blockquote><p>缺点是必须把项目放到webapps目录下</p><h3 id="_2-2-修改server-xml文件进行部署" tabindex="-1"><a class="header-anchor" href="#_2-2-修改server-xml文件进行部署" aria-hidden="true">#</a> 2.2. 修改server.xml文件进行部署</h3><ol><li>在Tomcat安装目录中找到<code>conf/server.xml</code>文件并打开；</li><li>在<code>&lt;Host&gt;</code>标签体中配置 <code>&lt;Context docBase=&quot;D:\\hello&quot; path=&quot;/hehe&quot; /&gt;</code></li></ol><blockquote><p>docBase:项目存放的路径；</p><p>path：虚拟目录。</p></blockquote><ol start="3"><li>双击bin/startup.bat文件启动服务器；</li><li>在浏览器中访问WEB项目。</li></ol><figure><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/java/JavaWeb/01.Tomcat/60be2dca844ef46bb2df16f5.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>缺点是需要到核心文件server.xml中去配置，在正式的WEB开发中很少会修改tomcat服务器的核心文件。</p><h3 id="_2-3-热部署" tabindex="-1"><a class="header-anchor" href="#_2-3-热部署" aria-hidden="true">#</a> 2.3. 热部署</h3><ol><li>在tomcat安装目录下<code>conf\\Catalina\\localhost</code>创建任意名称的xml文件，这里举例使用的是bbb.xml；</li><li>打开文件，在文件中编写代码 <code>&lt;Context docBase=&quot;D:\\hello&quot; /&gt;</code>；</li><li>启动服务器；</li><li>浏览该WEB项目。</li></ol><figure><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/java/JavaWeb/01.Tomcat/60be2d88844ef46bb2d8b118.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><blockquote><p>虚拟目录为xml文件的名称。</p></blockquote><p>优点：热部署。后续使用idea创建WEB项目时，idea使用的就是这种部署方式。</p>`,33);function m(_,f){const o=s("ExternalLinkIcon");return l(),i("div",null,[d,p,h,a("p",null,[e("在"),a("a",u,[e("Tomcat官网"),c(o)]),e("下载即可。")]),b])}const k=t(r,[["render",m],["__file","2.Tomcat-Introduction.html.vue"]]);export{k as default};
